import React, { useContext, useEffect, useState, useCallback } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { AuthContext } from '../App';
import { API_URL } from '../config';
import {
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip,
  ResponsiveContainer, AreaChart, Area,
} from 'recharts';

// ========== 成就徽章定义 ==========
const ACHIEVEMENT_DEFS = {
  first_workout:  { icon: '🏋️', name: '初次出征', desc: '完成第一次训练' },
  workout_10:     { icon: '🔟', name: '初级达人', desc: '累计完成10次训练' },
  workout_50:     { icon: '💪', name: '中级达人', desc: '累计完成50次训练' },
  workout_100:    { icon: '🏆', name: '健身王者', desc: '累计完成100次训练' },
  week_warrior:   { icon: '⚔️', name: '周间战士', desc: '累计训练7天' },
  month_master:   { icon: '👑', name: '月度主宰', desc: '累计训练30天' },
  streak_3:       { icon: '🔥', name: '三连打卡', desc: '连续打卡3天' },
  streak_7:       { icon: '🌟', name: '一周连打', desc: '连续打卡7天' },
  streak_30:      { icon: '💎', name: '月度不间断', desc: '连续打卡30天' },
  volume_10k:     { icon: '🏗️', name: '万斤举铁', desc: '累计力量总量超10,000kg' },
  volume_100k:    { icon: '🚀', name: '十万吨级', desc: '累计力量总量超100,000kg' },
};

// ========== 子组件 ==========

const StatCard = ({ title, value, unit, color, subtitle }) => (
  <div className="stat-card" style={color ? {
    background: `rgba(${color}, 0.05)`,
    border: `1px solid rgba(${color}, 0.15)`,
  } : {}}>
    <h3 style={color ? { color: `rgb(${color})` } : {}}>{title}</h3>
    <p className="stat-value" style={color ? { color: `rgb(${color})` } : {}}>
      {value}
    </p>
    {unit && <span className="stat-unit">{unit}</span>}
    {subtitle && <span className="stat-subtitle">{subtitle}</span>}
  </div>
);

const StreakCard = ({ streak }) => {
  const fire = streak >= 7 ? '🔥' : streak >= 3 ? '✨' : '💡';
  return (
    <div className="streak-card">
      <div className="streak-icon">{fire}</div>
      <div className="streak-info">
        <div className="streak-number">{streak}</div>
        <div className="streak-label">天连续打卡</div>
      </div>
      <div className="streak-tip">
        {streak === 0
          ? '今天开始打卡，建立习惯！'
          : streak < 3
          ? `再坚持 ${3 - streak} 天解锁徽章`
          : streak < 7
          ? `再坚持 ${7 - streak} 天解锁一周连打`
          : '保持势头，你很棒！'}
      </div>
    </div>
  );
};

const AchievementBadge = ({ id, unlocked }) => {
  const def = ACHIEVEMENT_DEFS[id];
  if (!def) return null;
  return (
    <div className={`achievement-badge ${unlocked ? 'unlocked' : 'locked'}`} title={def.desc}>
      <span className="badge-icon">{def.icon}</span>
      <span className="badge-name">{def.name}</span>
    </div>
  );
};

const BodyWeightModal = ({ onClose, onSave }) => {
  const [weight, setWeight] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-card" onClick={e => e.stopPropagation()}>
        <h3>记录今日体重</h3>
        <label>日期</label>
        <input type="date" value={date} onChange={e => setDate(e.target.value)} />
        <label>体重 (kg)</label>
        <input
          type="number"
          step="0.1"
          min="20"
          max="300"
          placeholder="例如：72.5"
          value={weight}
          onChange={e => setWeight(e.target.value)}
          autoFocus
        />
        <div style={{ display: 'flex', gap: 10, marginTop: 10 }}>
          <button onClick={() => { if (weight) onSave(date, parseFloat(weight)); }} style={{ flex: 1 }}>
            保存
          </button>
          <button className="secondary" onClick={onClose} style={{ flex: 1 }}>取消</button>
        </div>
      </div>
    </div>
  );
};

const ProgressModal = ({ exercise, onClose, token }) => {
  const [data, setData] = useState([]);
  useEffect(() => {
    fetch(`${API_URL}/api/workouts/progress/${encodeURIComponent(exercise)}`, {
      headers: { 'x-auth-token': token },
    })
      .then(r => r.json())
      .then(d => setData(d));
  }, [exercise, token]);

  const chartData = data.map(d => ({
    date: new Date(d.date).toLocaleDateString('zh-CN', { month: 'numeric', day: 'numeric' }),
    weight: d.bestWeight,
    volume: d.totalVolume,
  }));

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-card wide" onClick={e => e.stopPropagation()}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
          <h3 style={{ margin: 0 }}>{exercise} — 进步曲线</h3>
          <button className="secondary" onClick={onClose} style={{ padding: '6px 14px' }}>关闭</button>
        </div>
        {chartData.length < 2 ? (
          <p style={{ color: 'var(--apple-text-secondary)', textAlign: 'center', padding: 40 }}>
            至少需要2次训练记录才能显示进步曲线
          </p>
        ) : (
          <ResponsiveContainer width="100%" height={220}>
            <AreaChart data={chartData}>
              <defs>
                <linearGradient id="weightGrad" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#0071e3" stopOpacity={0.15} />
                  <stop offset="95%" stopColor="#0071e3" stopOpacity={0} />
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="rgba(0,0,0,0.05)" />
              <XAxis dataKey="date" tick={{ fill: 'var(--apple-text-secondary)', fontSize: 12 }} axisLine={false} tickLine={false} />
              <YAxis tick={{ fill: 'var(--apple-text-secondary)', fontSize: 12 }} axisLine={false} tickLine={false} unit="kg" />
              <Tooltip
                contentStyle={{ borderRadius: 12, border: 'none', boxShadow: '0 4px 24px rgba(0,0,0,0.1)' }}
                formatter={(v) => [`${v} kg`, '最高重量']}
              />
              <Area type="monotone" dataKey="weight" stroke="#0071e3" strokeWidth={2.5} fill="url(#weightGrad)" dot={{ r: 4, fill: '#0071e3' }} />
            </AreaChart>
          </ResponsiveContainer>
        )}
      </div>
    </div>
  );
};

// ========== 主 Dashboard ==========

const Dashboard = () => {
  const { token, user, logout } = useContext(AuthContext);
  const [workouts, setWorkouts] = useState([]);
  const [stats, setStats] = useState(null);
  const [prs, setPrs] = useState([]);
  const [bodyWeightLog, setBodyWeightLog] = useState([]);
  const [period, setPeriod] = useState('all'); // 'week' | 'month' | 'all'
  const [showBodyWeightModal, setShowBodyWeightModal] = useState(false);
  const [progressExercise, setProgressExercise] = useState(null);
  const [activeTab, setActiveTab] = useState('history'); // 'history' | 'pr' | 'body'
  const navigate = useNavigate();

  const fetchAll = useCallback(async () => {
    if (!token) return;
    try {
      const [wRes, sRes, prRes, bwRes] = await Promise.all([
        fetch(`${API_URL}/api/workouts?period=${period}`, { headers: { 'x-auth-token': token } }),
        fetch(`${API_URL}/api/workouts/stats`, { headers: { 'x-auth-token': token } }),
        fetch(`${API_URL}/api/workouts/pr`, { headers: { 'x-auth-token': token } }),
        fetch(`${API_URL}/api/workouts/body-weight`, { headers: { 'x-auth-token': token } }),
      ]);

      if (wRes.ok) setWorkouts(await wRes.json());
      if (sRes.ok) setStats(await sRes.json());
      if (prRes.ok) setPrs(await prRes.json());
      if (bwRes.ok) setBodyWeightLog(await bwRes.json());
    } catch (err) {
      console.error('Failed to fetch dashboard data:', err);
    }
  }, [token, period]);

  useEffect(() => {
    fetchAll();
  }, [fetchAll]);

  const handleDelete = async (id) => {
    if (!window.confirm('确认删除这条训练记录？')) return;
    try {
      const res = await fetch(`${API_URL}/api/workouts/${id}`, {
        method: 'DELETE',
        headers: { 'x-auth-token': token },
      });
      if (res.ok) {
        setWorkouts(workouts.filter(w => w._id !== id));
        // 刷新统计
        fetchAll();
      }
    } catch (err) {
      console.error(err);
    }
  };

  const handleDeleteSet = async (workoutId, setIndex) => {
    try {
      const res = await fetch(`${API_URL}/api/workouts/${workoutId}/set/${setIndex}`, {
        method: 'DELETE',
        headers: { 'x-auth-token': token },
      });
      if (res.ok) {
        const result = await res.json();
        if (result.deleted) {
          setWorkouts(workouts.filter(w => w._id !== workoutId));
        } else {
          setWorkouts(workouts.map(w => w._id === workoutId ? result : w));
        }
      }
    } catch (err) {
      console.error(err);
    }
  };

  const handleSaveBodyWeight = async (date, weight) => {
    try {
      const res = await fetch(`${API_URL}/api/workouts/body-weight`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'x-auth-token': token },
        body: JSON.stringify({ date, weight }),
      });
      if (res.ok) {
        const log = await res.json();
        setBodyWeightLog(log);
        setShowBodyWeightModal(false);
      }
    } catch (err) {
      console.error(err);
    }
  };

  // 按日期分组
  const groupedWorkouts = workouts.reduce((acc, w) => {
    const rawDate = new Date(w.date);
    const dateStr = rawDate.toLocaleDateString('zh-CN', { month: 'long', day: 'numeric', weekday: 'long' });
    if (!acc[dateStr]) acc[dateStr] = { rawDate, items: [], totalVol: 0, totalCals: 0 };
    acc[dateStr].items.push(w);
    if (w.type === 'strength') {
      acc[dateStr].totalVol += w.sets.reduce((s, set) => s + set.weight * set.reps, 0);
    } else {
      acc[dateStr].totalCals += w.sets.reduce((s, set) => s + (set.reps || 0), 0);
    }
    return acc;
  }, {});

  const sortedDates = Object.keys(groupedWorkouts).sort(
    (a, b) => groupedWorkouts[b].rawDate - groupedWorkouts[a].rawDate
  );

  // 折线图数据：按日期汇总力量总量
  const chartData = [...sortedDates].reverse().map(dateKey => ({
    date: groupedWorkouts[dateKey].rawDate.toLocaleDateString('zh-CN', { month: 'numeric', day: 'numeric' }),
    totalWeight: groupedWorkouts[dateKey].totalVol,
  })).filter(d => d.totalWeight > 0);

  // 体重图数据
  const bwChartData = [...bodyWeightLog]
    .sort((a, b) => new Date(a.date) - new Date(b.date))
    .slice(-30)
    .map(e => ({
      date: new Date(e.date).toLocaleDateString('zh-CN', { month: 'numeric', day: 'numeric' }),
      weight: e.weight,
    }));

  const latestBodyWeight = bodyWeightLog.length > 0
    ? bodyWeightLog.sort((a, b) => new Date(b.date) - new Date(a.date))[0].weight
    : null;

  return (
    <div>
      {/* Nav */}
      <nav className="nav">
        <h1 className="nav-brand">💪 FitTrack</h1>
        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          {user && <span className="nav-greeting" style={{ fontWeight: 500 }}>{user.username}</span>}
          <Link to="/add"><button style={{ padding: '8px 18px', fontSize: 14 }}>+ 记录训练</button></Link>
          <button className="secondary" onClick={() => setShowBodyWeightModal(true)} style={{ padding: '8px 14px', fontSize: 14 }}>
            记录体重
          </button>
          <button className="secondary" onClick={logout} style={{ padding: '8px 14px', fontSize: 14 }}>退出</button>
        </div>
      </nav>

      {/* Hero */}
      <div className="hero-section">
        <h1 style={{ marginTop: 40, marginBottom: 8 }}>
          {user ? `欢迎回来，${user.username}` : '今天准备好了吗'}
        </h1>
        <p style={{ color: 'var(--apple-text-secondary)', fontSize: 17, marginBottom: 32 }}>
          {stats && stats.streak > 0
            ? `你已连续打卡 ${stats.streak} 天，保持下去`
            : '记录每一次训练，见证自己的成长'}
        </p>
      </div>

      {/* Streak + Stats */}
      <div className="dashboard-top">
        {stats && <StreakCard streak={stats.streak} />}

        <div className="stats-grid">
          <StatCard title="训练次数" value={stats?.totalWorkouts ?? '—'} />
          <StatCard title="活跃天数" value={stats?.activeDays ?? '—'} />
          <StatCard
            title="力量总量"
            value={stats ? stats.totalVolume.toLocaleString() : '—'}
            unit="kg"
            color="0, 113, 227"
          />
          <StatCard
            title="有氧消耗"
            value={stats?.totalCardioCalories ?? '—'}
            unit="大卡"
            color="255, 149, 0"
          />
          {latestBodyWeight && (
            <StatCard
              title="当前体重"
              value={latestBodyWeight}
              unit="kg"
              color="52, 199, 89"
              subtitle="点击更新"
            />
          )}
        </div>
      </div>

      {/* 成就徽章 */}
      {stats && stats.achievements.length > 0 && (
        <div className="achievements-section">
          <h3>成就</h3>
          <div className="achievements-row">
            {Object.keys(ACHIEVEMENT_DEFS).map(id => (
              <AchievementBadge key={id} id={id} unlocked={stats.achievements.includes(id)} />
            ))}
          </div>
        </div>
      )}

      {/* 主内容区 Tabs */}
      <div className="content-tabs">
        {[
          { key: 'history', label: '训练历史' },
          { key: 'pr', label: '个人记录 PR' },
          { key: 'body', label: '体重趋势' },
        ].map(tab => (
          <div
            key={tab.key}
            className={`content-tab ${activeTab === tab.key ? 'active' : ''}`}
            onClick={() => setActiveTab(tab.key)}
          >
            {tab.label}
          </div>
        ))}
      </div>

      {/* 训练历史 Tab */}
      {activeTab === 'history' && (
        <>
          {/* 时间维度筛选 */}
          <div className="period-filter">
            {[
              { key: 'week', label: '近7天' },
              { key: 'month', label: '近30天' },
              { key: 'all', label: '全部' },
            ].map(p => (
              <button
                key={p.key}
                className={period === p.key ? '' : 'secondary'}
                style={{ padding: '6px 16px', fontSize: 14 }}
                onClick={() => setPeriod(p.key)}
              >
                {p.label}
              </button>
            ))}
          </div>

          {/* 力量总量趋势图 */}
          {chartData.length >= 2 && (
            <div className="chart-container" style={{ marginBottom: 32 }}>
              <h3>力量训练量趋势</h3>
              <ResponsiveContainer width="100%" height={200}>
                <AreaChart data={chartData}>
                  <defs>
                    <linearGradient id="volGrad" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#0071e3" stopOpacity={0.12} />
                      <stop offset="95%" stopColor="#0071e3" stopOpacity={0} />
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="rgba(0,0,0,0.05)" />
                  <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{ fill: 'var(--apple-text-secondary)', fontSize: 12 }} />
                  <YAxis axisLine={false} tickLine={false} tick={{ fill: 'var(--apple-text-secondary)', fontSize: 12 }} />
                  <Tooltip
                    contentStyle={{ borderRadius: 12, border: 'none', boxShadow: '0 4px 24px rgba(0,0,0,0.1)' }}
                    formatter={v => [`${v.toLocaleString()} kg`, '训练量']}
                  />
                  <Area type="monotone" dataKey="totalWeight" stroke="#0071e3" strokeWidth={2.5} fill="url(#volGrad)" dot={{ r: 3, fill: '#0071e3' }} />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          )}

          {/* 历史记录列表 */}
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
            <h2 style={{ margin: 0 }}>最近活动</h2>
          </div>

          {workouts.length === 0 ? (
            <div className="empty-state">
              <div className="empty-icon">🏋️</div>
              <h3>你的训练之旅从这里开始</h3>
              <p>还没有训练记录，去记录你的第一次训练吧！</p>
              <Link to="/add"><button style={{ marginTop: 20 }}>开始第一次训练</button></Link>
            </div>
          ) : (
            <div className="daily-groupings">
              {sortedDates.map(dateKey => {
                const dayData = groupedWorkouts[dateKey];
                return (
                  <div key={dateKey} className="daily-group">
                    <div className="daily-header">
                      <h3>{dateKey}</h3>
                      <div style={{ display: 'flex', gap: 12 }}>
                        {dayData.totalVol > 0 && (
                          <span className="daily-meta">容量 {dayData.totalVol.toLocaleString()} kg</span>
                        )}
                        {dayData.totalCals > 0 && (
                          <span className="daily-meta" style={{ color: '#ff9500' }}>
                            🔥 {dayData.totalCals} 千卡
                          </span>
                        )}
                      </div>
                    </div>

                    {dayData.items.map(w => (
                      <div key={w._id} className={`exercise-card ${w.type === 'cardio' ? 'cardio-card' : ''}`}>
                        <div className="exercise-header">
                          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                            <span style={{ fontSize: 20 }}>{w.type === 'cardio' ? '🏃' : '🏋️'}</span>
                            <div>
                              <h4 style={{ margin: 0 }}>{w.exercise}</h4>
                              {w.type === 'strength' && (
                                <span
                                  className="progress-link"
                                  onClick={() => setProgressExercise(w.exercise)}
                                >
                                  查看进步曲线 →
                                </span>
                              )}
                            </div>
                          </div>
                          <button className="delete-btn" onClick={() => handleDelete(w._id)}>删除</button>
                        </div>

                        <div className="set-list">
                          {w.sets.map((s, i) => (
                            <div key={i} className="set-item">
                              {w.type === 'strength' && <span className="set-item-index">#{i + 1}</span>}
                              {w.type === 'cardio' ? (
                                <>
                                  <span>{s.weight} 分钟</span>
                                  <span style={{ color: '#ff9500' }}>{s.reps} 大卡</span>
                                </>
                              ) : (
                                <>
                                  <span>{s.weight === 0 ? '自重' : `${s.weight} kg`}</span>
                                  <span>{s.reps} 次</span>
                                </>
                              )}
                              <button
                                className="set-delete-btn"
                                title="删除这组"
                                onClick={() => handleDeleteSet(w._id, i)}
                              >
                                ×
                              </button>
                            </div>
                          ))}
                        </div>

                        {w.notes && (
                          <div className="exercise-notes">{w.notes}</div>
                        )}
                      </div>
                    ))}
                  </div>
                );
              })}
            </div>
          )}
        </>
      )}

      {/* PR Tab */}
      {activeTab === 'pr' && (
        <div>
          <h2 style={{ marginBottom: 20 }}>个人最佳记录</h2>
          {prs.length === 0 ? (
            <div className="empty-state">
              <div className="empty-icon">🏆</div>
              <h3>还没有PR记录</h3>
              <p>完成力量训练后，你的个人最佳记录将在这里展示。</p>
            </div>
          ) : (
            <div className="pr-list">
              {prs.map((pr, idx) => (
                <div key={pr.exercise} className="pr-card">
                  <div className="pr-rank">{idx + 1 <= 3 ? ['🥇', '🥈', '🥉'][idx] : `#${idx + 1}`}</div>
                  <div className="pr-info">
                    <div className="pr-exercise">{pr.exercise}</div>
                    <div className="pr-date">
                      {new Date(pr.date).toLocaleDateString('zh-CN', { year: 'numeric', month: 'long', day: 'numeric' })}
                    </div>
                  </div>
                  <div className="pr-stats">
                    <div className="pr-weight">{pr.weight === 0 ? '自重' : `${pr.weight} kg`}</div>
                    <div className="pr-reps">× {pr.reps} 次</div>
                  </div>
                  <button
                    className="secondary"
                    style={{ fontSize: 13, padding: '6px 12px' }}
                    onClick={() => { setProgressExercise(pr.exercise); }}
                  >
                    进步曲线
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* 体重趋势 Tab */}
      {activeTab === 'body' && (
        <div>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
            <h2 style={{ margin: 0 }}>体重趋势</h2>
            <button onClick={() => setShowBodyWeightModal(true)} style={{ padding: '8px 18px', fontSize: 14 }}>
              + 记录体重
            </button>
          </div>

          {bwChartData.length < 2 ? (
            <div className="empty-state">
              <div className="empty-icon">⚖️</div>
              <h3>开始记录你的体重</h3>
              <p>坚持每天记录，追踪身体变化趋势。</p>
              <button style={{ marginTop: 20 }} onClick={() => setShowBodyWeightModal(true)}>
                记录今日体重
              </button>
            </div>
          ) : (
            <div className="chart-container">
              <h3>近30天体重变化</h3>
              <ResponsiveContainer width="100%" height={250}>
                <AreaChart data={bwChartData}>
                  <defs>
                    <linearGradient id="bwGrad" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#34c759" stopOpacity={0.15} />
                      <stop offset="95%" stopColor="#34c759" stopOpacity={0} />
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="rgba(0,0,0,0.05)" />
                  <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{ fill: 'var(--apple-text-secondary)', fontSize: 12 }} />
                  <YAxis
                    axisLine={false} tickLine={false}
                    tick={{ fill: 'var(--apple-text-secondary)', fontSize: 12 }}
                    unit="kg"
                    domain={['auto', 'auto']}
                  />
                  <Tooltip
                    contentStyle={{ borderRadius: 12, border: 'none', boxShadow: '0 4px 24px rgba(0,0,0,0.1)' }}
                    formatter={v => [`${v} kg`, '体重']}
                  />
                  <Area type="monotone" dataKey="weight" stroke="#34c759" strokeWidth={2.5} fill="url(#bwGrad)" dot={{ r: 4, fill: '#34c759' }} activeDot={{ r: 6 }} />
                </AreaChart>
              </ResponsiveContainer>

              {/* 体重历史列表 */}
              <div className="bw-log">
                {[...bodyWeightLog]
                  .sort((a, b) => new Date(b.date) - new Date(a.date))
                  .slice(0, 10)
                  .map((e, i) => (
                    <div key={i} className="bw-item">
                      <span>{new Date(e.date).toLocaleDateString('zh-CN', { month: 'long', day: 'numeric' })}</span>
                      <span className="bw-value">{e.weight} kg</span>
                    </div>
                  ))}
              </div>
            </div>
          )}
        </div>
      )}

      {/* 进步曲线模态框 */}
      {progressExercise && (
        <ProgressModal
          exercise={progressExercise}
          onClose={() => setProgressExercise(null)}
          token={token}
        />
      )}

      {/* 体重记录模态框 */}
      {showBodyWeightModal && (
        <BodyWeightModal
          onClose={() => setShowBodyWeightModal(false)}
          onSave={handleSaveBodyWeight}
        />
      )}
    </div>
  );
};

export default Dashboard;
